function error(err, req, res, next) {
  // log it
  if (!test) console.error(err.stack);

  // respond with 500 "Internal Server Error".
  res.status(500);
  res.send('Internal Server Error');
}

app.get('/', function () {
  // Caught and passed down to the errorHandler middleware
  throw new Error('something broke!');
});

app.get('/next', function(req, res, next){
  // We can also pass exceptions to next()
  // The reason for process.nextTick() is to show that
  // next() can be called inside an async operation,
  // in real life it can be a DB read or HTTP request.
  process.nextTick(function(){
    next(new Error('oh no!'));
  });
});

// the error handler is placed after routes
// if it were above it would not receive errors
// from app.get() etc
app.use(error);

if (config.backchannelLogout) {
  const path = enforceLeadingSlash(config.routes.backchannelLogout);
  debug('adding POST %s route', path);
  router.post(path, express.urlencoded({ extended: false }), (req, res) =>
    res.oidc.backchannelLogout(),
  );

  if (config.backchannelLogout.isLoggedOut !== false) {
    const isLoggedOutFn = config.backchannelLogout.isLoggedOut || isLoggedOut;
    router.use(async (req, res, next) => {
      if (!req.oidc.isAuthenticated()) {
        next();
        return;
      }
      try {
        const loggedOut = await isLoggedOutFn(req, config);
        if (loggedOut) {
          req[config.session.name] = undefined;
        }
        next();
      } catch (e) {
        next(e);
      }
    });
  }
}

Strategy.prototype.authenticate = function(req, options) {
  options = options || {};
  var username = lookup(req.body, this._usernameField) || lookup(req.query, this._usernameField);
  var password = lookup(req.body, this._passwordField) || lookup(req.query, this._passwordField);

  if (!username || !password) {
    return this.fail({ message: options.badRequestMessage || 'Missing credentials' }, 400);
  }

  var self = this;

  function verified(err, user, info) {
    if (err) { return self.error(err); }
    if (!user) { return self.fail(info); }
    self.success(user, info);
  }

  try {
    if (self._passReqToCallback) {
      this._verify(req, username, password, verified);
    } else {
      this._verify(username, password, verified);
    }
  } catch (ex) {
    return self.error(ex);
  }
};

extractors.versionOneCompatibility = function (options) {
    var authScheme = options.authScheme || LEGACY_AUTH_SCHEME,
        bodyField = options.tokenBodyField || 'auth_token',
        queryParam = options.tokenQueryParameterName || 'auth_token';

    return function (request) {
        var authHeaderExtractor = extractors.fromAuthHeaderWithScheme(authScheme);
        var token =  authHeaderExtractor(request);

        if (!token) {
            var bodyExtractor = extractors.fromBodyField(bodyField);
            token = bodyExtractor(request);
        }

        if (!token) {
            var queryExtractor = extractors.fromUrlQueryParameter(queryParam);
            token = queryExtractor(request);
        }

        return token;
    };
}

for (const call of nodes) {
  const arg = call.getMatch('ARG')
  const obj = call.getMatch('OBJ')
  if (!arg || !obj) continue

  if (getStringLiteralValue(arg) !== 'back') continue

  const objDef = obj.definition({ resolveExternal: false })
  if (!objDef) continue

  const isParameter = objDef.node.matches({
    rule: { inside: { kind: 'formal_parameters', stopBy: 'end' } },
  })
  if (!isParameter) continue

  const parameters = findParentFunctionParameters(objDef.node)
  if (!parameters) continue

  const firstParameter = parameters.find({ rule: { kind: 'identifier' } })
  if (!firstParameter) continue

  const requestName = firstParameter.text()

  edits.push(arg.replace(`${requestName}.get("Referrer") || "/"`))
}

@injectable({scope: BindingScope.SINGLETON})
  class HealthController {
    constructor(
      @inject(HealthBindings.HEALTH_CHECKER)
      private healthChecker: HealthChecker,
    ) {}

    @get(options.healthPath, spec)
    async health(@inject(RestBindings.Http.RESPONSE) response: Response) {
      const status = await this.healthChecker.getStatus();
      return handleStatus(response, status);
    }

    @get(options.readyPath, spec)
    async ready(@inject(RestBindings.Http.RESPONSE) response: Response) {
      const status = await this.healthChecker.getReadinessStatus();
      return handleStatus(response, status, 503);
    }

    @get(options.livePath, spec)
    async live(@inject(RestBindings.Http.RESPONSE) response: Response) {
      const status = await this.healthChecker.getLivenessStatus();
      return handleStatus(response, status, 500);
    }
  }

